VALUES
  ('disabled-e3452428-moex-00017', 'disabled-e3452428', 'disabled-e3452428-moex-114-decd973b', 'sub-disabled-e3452428-02', NULL, 'single_choice', '依憲法增修條文及司法院大法官解釋，關於行政院院長，下列敘述何者 錯誤？', '["總統發布行政院院長的免職令，無須行政院院長副署", "有關行政院院長的任期，並無明文規定", "立法院對行政院院長所提出的不信任案如未獲通過，不得對同一行政院 院長再提不信任案", "總統藉由其任命的行政院院長，變更先前存在，與其政見未洽之施政方 針或政策，屬政黨政治常態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:16+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般民政"}'::jsonb, NULL),
  ('disabled-e3452428-moex-00018', 'disabled-e3452428', 'disabled-e3452428-moex-114-decd973b', 'sub-disabled-e3452428-02', NULL, 'single_choice', '憲法第 73 條規定，立法委員在院內所為之言論及表決，對院外不負責 任。依司法院釋字第435號，關於立法委員之言論免責權，下列敘述何者 錯誤？', '["司法機關為維護社會秩序及被害人權益，對於立法委員行為是否逾越免 責保障之範圍，於必要時得依法行使偵審之權限", "舉凡在院會或委員會之發言、質詢、提案、表決以及與此直接相關之附 隨行為，均屬應予保障之事項", "與行使職權無關之行為，諸如蓄意之肢體動作等，顯然不符意見表達之 適當情節致侵害他人法益者，不在保障之列", "言論免責權為憲法賦予立法委員之例外特權，故其保障範圍應作最小程 度之嚴格界定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:16+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般民政"}'::jsonb, NULL),
  ('disabled-e3452428-moex-00019', 'disabled-e3452428', 'disabled-e3452428-moex-114-decd973b', 'sub-disabled-e3452428-02', NULL, 'single_choice', '下列何者之自治權，受憲法保障？', '["鄉（鎮、市）", "獨立行政機關", "大學", "祭祀公業"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:16+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般民政"}'::jsonb, NULL),
  ('disabled-e3452428-moex-00020', 'disabled-e3452428', 'disabled-e3452428-moex-114-decd973b', 'sub-disabled-e3452428-02', NULL, 'single_choice', '下列何項敘述，符合司法院大法官就「法律明確性原則」所闡釋之內容？', '["法律明確性之要求，指法律文義須具體詳盡", "立法者於制定法律時，不得運用不確定法律概念", "法律規定是否明確，得自法條文義、立法目的與法體系整體關聯性觀察 得知", "是否違反法律明確性原則與法規範之意義得否由司法審查加以確認一 事無關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:16+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般民政"}'::jsonb, NULL),
  ('disabled-e3452428-moex-00021', 'disabled-e3452428', 'disabled-e3452428-moex-114-decd973b', 'sub-disabled-e3452428-02', NULL, 'single_choice', '有關「行政裁量」與「不確定法律概念」之區別，下列敘述何者正確？', '["不確定法律概念僅存在於公法法規", "在行政裁量範圍內的各項選擇原則上僅生適當與否的問題", "行政機關就不確定法律概念享有判斷餘地時，行政法院以介入審查為 原則", "就行政機關之裁量，行政法院得為妥當性之審查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:16+00:00", "source_pdf_sha1": "0c2a462631d6", "answer_pdf_sha1": "0408f66f88b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基礎能力測驗(作文、中華民國憲法及法學緒論)", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般民政"}'::jsonb, NULL),
